/**
 * Setup banner dismiss handler.
 *
 * Calls block_mastermind_assistant_complete_setup, then removes the banner DOM.
 *
 * @module     block_mastermind_assistant/setup_banner
 * @copyright  2026 The Namers <info@mastermindassistant.ai>
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define(['core/ajax', 'core/notification'], function(Ajax, Notification) {
    return {
        /**
         * Wire the banner's Dismiss button.
         */
        init: function() {
            var btn = document.getElementById('mastermind-setup-dismiss');
            if (!btn) {
                return;
            }
            btn.addEventListener('click', function() {
                btn.disabled = true;
                Ajax.call([{
                    methodname: 'block_mastermind_assistant_complete_setup',
                    args: {}
                }])[0].then(function() {
                    var banner = document.getElementById('mastermind-setup-banner');
                    if (banner && banner.parentNode) {
                        banner.parentNode.removeChild(banner);
                    }
                    return null;
                }).catch(function(err) {
                    btn.disabled = false;
                    Notification.exception(err);
                });
            });
        }
    };
});
